export function runBaselineAnalysis() {
  let total = 0;

  for (let pass = 0; pass < 36; pass += 1) {
    for (let index = 0; index < baselineCoefficients.length; index += 1) {
      const value = baselineCoefficients[index];
      total += Math.sqrt(value + pass) * Math.sin(value / 17);
    }
  }

  return Number(total.toFixed(3));
}
